import React from "react";
import {
  Archive,
  Bell,
  Clock,
  Copy,
  Edit2,
  History,
  Pin,
  Share2,
  Star,
  Trash2,
  Eye,
} from "lucide-react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";

const NoteCard = ({
  note,
  viewMode,
  showTrash,
  selectedNotes,
  toggleNoteSelection,
  togglePin,
  toggleFavorite,
  toggleArchive,
  deleteNote,
  duplicateNote,
  fetchVersions,
  openShareModal,
  updateChecklistItem,
  expandedChecklistIds,
  toggleExpandChecklist,
  categories,
  setEditingNote,
  setViewingNote,
}) => {
  const isExpanded = !!expandedChecklistIds[note._id];
  const itemsToShow =
    isExpanded || !note.checklist || note.checklist.length <= 3
      ? note.checklist || []
      : note.checklist.slice(0, 3);

  return (
    <div
      className={`group relative rounded-2xl p-6 shadow-lg hover:shadow-2xl transition-all duration-300 ${
        viewMode === "grid" ? "transform hover:-translate-y-1" : ""
      } ${note.isPinned ? "ring-2 ring-blue-500" : ""}`}
      style={{ backgroundColor: note.color }}
    >
      {note.isPinned && (
        <div className="absolute -top-2 -right-2 bg-blue-500 text-white rounded-full p-2 shadow-lg">
          <Pin size={14} />
        </div>
      )}

      {!showTrash && (
        <div className="absolute top-3 left-3 z-10">
          <input
            type="checkbox"
            checked={selectedNotes.includes(note._id)}
            onChange={(e) => {
              e.stopPropagation();
              toggleNoteSelection(note._id);
            }}
            className="w-5 h-5 cursor-pointer rounded border-2 border-gray-400 checked:bg-blue-500 checked:border-blue-500 transition-all"
            title="Chon ghi chu"
          />
        </div>
      )}

      <div className="absolute top-3 right-3 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
        <button
          onClick={() => togglePin(note)}
          className="p-2 bg-white bg-opacity-80 rounded-full shadow-md hover:bg-opacity-100 transition-all"
          title="Ghim ghi chu"
        >
          <Pin
            size={14}
            className={note.isPinned ? "text-blue-600" : "text-gray-400"}
          />
        </button>
        <button
          onClick={() => toggleFavorite(note)}
          className="p-2 bg-white bg-opacity-80 rounded-full shadow-md hover:bg-opacity-100 transition-all"
          title="Yeu thich"
        >
          <Star
            size={14}
            className={
              note.isFavorite
                ? "text-yellow-500 fill-yellow-500"
                : "text-gray-400"
            }
          />
        </button>
      </div>

      <h3 className="text-xl font-bold mb-3 pr-20 text-gray-800">{note.title}</h3>

      {note.checklist && note.checklist.length > 0 && (
        <div className="mb-3 space-y-2">
          {itemsToShow.map((item, idx) => (
            <label key={idx} className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={item.checked}
                onChange={(e) =>
                  updateChecklistItem(note, idx, e.target.checked)
                }
                className="w-4 h-4"
              />
              <span
                className={`text-sm ${
                  item.checked ? "line-through text-gray-500" : "text-gray-700"
                }`}
              >
                {item.text}
              </span>
            </label>
          ))}
          {note.checklist.length > 3 && (
            <button
              className="text-xs text-blue-700 underline"
              onClick={() => toggleExpandChecklist(note._id)}
            >
              {isExpanded
                ? "Thu gon"
                : `Xem them +${note.checklist.length - 3} muc`}
            </button>
          )}
        </div>
      )}

      <div className="mb-3 line-clamp-3">
        {note.isMarkdown ? (
          <div className="prose prose-sm dark:prose-invert max-w-none">
            <ReactMarkdown remarkPlugins={[remarkGfm]}>
              {note.content}
            </ReactMarkdown>
          </div>
        ) : (
          <p className="text-gray-700 whitespace-pre-wrap">{note.content}</p>
        )}
      </div>

      {note.reminder && (
        <div className="mb-3 flex items-center gap-2 text-xs text-orange-700 bg-orange-100 bg-opacity-60 px-2 py-1 rounded-full">
          <Bell size={12} />
          Nhac: {new Date(note.reminder).toLocaleString("vi-VN")}
        </div>
      )}

      {note.tags && note.tags.length > 0 && (
        <div className="flex flex-wrap gap-2 mb-3">
          {note.tags.slice(0, 3).map((tag, idx) => (
            <span
              key={idx}
              className="px-2 py-1 bg-white bg-opacity-60 rounded-full text-xs font-semibold text-gray-700"
            >
              #{tag}
            </span>
          ))}
          {note.tags.length > 3 && (
            <span className="px-2 py-1 bg-white bg-opacity-60 rounded-full text-xs font-semibold text-gray-700">
              +{note.tags.length - 3}
            </span>
          )}
        </div>
      )}

      <div className="flex items-center justify-between text-xs text-gray-600 mb-3">
        <div className="flex items-center gap-1">
          <Clock size={12} />
          {note.createdAt
            ? new Date(note.createdAt).toLocaleDateString("vi-VN", {
                day: "2-digit",
                month: "2-digit",
                year: "numeric",
              })
            : ""}
        </div>
        <span className="px-2 py-1 bg-white bg-opacity-60 rounded-full text-xs font-semibold">
          {categories.find((category) => category.id === note.category)?.name ||
            "Ca nhan"}
        </span>
      </div>

      <div className="grid grid-cols-7 gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
        <button
          onClick={() => setViewingNote(note)}
          className="flex items-center justify-center p-2 bg-teal-500 text-white rounded-lg hover:bg-teal-600 transition-colors"
          title="Xem chi tiết"
        >
          <Eye size={14} />
        </button>
        <button
          onClick={() => setEditingNote(note)}
          className="flex items-center justify-center p-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors"
          title="Sửa"
        >
          <Edit2 size={14} />
        </button>
        <button
          onClick={() => duplicateNote(note)}
          className="flex items-center justify-center p-2 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors"
          title="Sao chep"
        >
          <Copy size={14} />
        </button>
        <button
          onClick={() => openShareModal(note)}
          className="flex items-center justify-center p-2 bg-purple-500 text-white rounded-lg hover:bg-purple-600 transition-colors"
          title="Chia se"
        >
          <Share2 size={14} />
        </button>
        <button
          onClick={() => fetchVersions(note._id)}
          className="flex items-center justify-center p-2 bg-indigo-500 text-white rounded-lg hover:bg-indigo-600 transition-colors"
          title="Lich su"
        >
          <History size={14} />
        </button>
        <button
          onClick={() => toggleArchive(note)}
          className="flex items-center justify-center p-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors"
          title={note.isArchived ? "Bo luu tru" : "Luu tru"}
        >
          <Archive size={14} />
        </button>
        <button
          onClick={() => deleteNote(note._id)}
          className="flex items-center justify-center p-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors"
          title="Xoa"
        >
          <Trash2 size={14} />
        </button>
      </div>
    </div>
  );
};

export default React.memo(NoteCard);
